final:
module RefModule (
    input clk,
    input [7:0] data_in,
    output reg [3:0] count
);

    integer obf_i;

    always @(posedge clk) begin
        count = 4'b0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            if (data_in[obf_i]) count = count + 1;
        end
    end
endmodule
